document.addEventListener("DOMContentLoaded",()=>{const navLinks=document.querySelectorAll(".nav-link");const sections=document.querySelectorAll(".section");navLinks.forEach(link=>{link.addEventListener("click",e=>{e.preventDefault();const targetId=link.getAttribute("data-target");navLinks.forEach(l=>l.classList.remove("active"));link.classList.add("active");sections.forEach(section=>{section.classList.remove("active");if(section.id===targetId){section.classList.add("active")}})})});const pace3minInput=document.getElementById("pace-3min");const pace9minInput=document.getElementById("pace-9min");const calcularRftpaBtn=document.getElementById("calcular-rftpa");const paceMediaElement=document.getElementById("pace-medio");const rftpaValueElement=document.getElementById("rftpa-value");const nivelAtletaElement=document.getElementById("nivel-atleta");function paceParaSegundos(paceStr){const[min,seg]=paceStr.split(":").map(num=>parseInt(num));return min*60+seg}function segundosParaPace(segundos){const min=Math.floor(segundos/60);const seg=Math.round(segundos%60);return`${min}:${seg.toString().padStart(2,"0")}`}calcularRftpaBtn.addEventListener("click",()=>{if(!pace3minInput.value||!pace9minInput.value){alert("Por favor, insira o pace para ambos os intervalos.");return}const pace3minSegundos=paceParaSegundos(pace3minInput.value);const pace9minSegundos=paceParaSegundos(pace9minInput.value);const paceMediaSegundos=(pace3minSegundos+pace9minSegundos)/2;const rftpaSegundos=paceMediaSegundos*1.1;const paceMediaStr=segundosParaPace(paceMediaSegundos);const rftpaStr=segundosParaPace(rftpaSegundos);paceMediaElement.textContent=`${paceMediaStr} min/km`;rftpaValueElement.textContent=`${rftpaStr} min/km`;const nivel=rftpaSegundos>=271?"N1":"N2";nivelAtletaElement.textContent=nivel;nivelAtletaElement.style.fontWeight="bold";nivelAtletaElement.style.color=nivel==="N1"?"#38B6FF":"#FF8012"});const formTeste=document.getElementById("form-teste");formTeste.addEventListener("submit",e=>{e.preventDefault();if(rftpaValueElement.textContent==="-"){alert("Por favor, calcule o rFTPa antes de gerar o relatório.");return}if(!formTeste.checkValidity()){formTeste.reportValidity();return}const alunoNome=document.getElementById("aluno-nome").value;const dataTeste=document.getElementById("data-teste").value;const pace3min=pace3minInput.value;const pace9min=pace9minInput.value;const paceMedia=paceMediaElement.textContent.replace(" min/km","");const rftpaValue=rftpaValueElement.textContent.replace(" min/km","");const nivelAtleta=nivelAtletaElement.textContent;const testeData={alunoNome:alunoNome,dataTeste:dataTeste,pace3min:pace3min,pace9min:pace9min,paceMedia:paceMedia,rftpa:rftpaValue,nivel:nivelAtleta,tipoTeste:"rftpa"};gerarRelatorio(testeData)})});function gerarRelatorio(data){const jsonData=JSON.stringify(data);const encodedData=encodeURIComponent(jsonData);window.open(`report-rftpa.html?data=${encodedData}`,"_blank")}